def decide(record: dict) -> str:
    required = {"case_id", "lint", "types", "tests", "matrix", "supported"}
    missing = sorted(required - record.keys())
    if missing:
        return "CONTINUE"
    return "CONTINUE" if record["lint"] or record["types"] or record["tests"] else "FAIL_CI_GATE"

valid = {"case_id": "CASO-PIU-044-1A", **{"lint":True,"types":True,"tests":True,"matrix":{"3.11","3.12"},"supported":{"3.11","3.12"}}}
invalid = {"case_id": "CASO-PIU-044-1A", **{"lint":True,"types":False,"tests":True,"matrix":{"3.10","3.12"},"supported":{"3.11","3.12"}}}
uncertain = {**valid}
uncertain.pop("supported")
results = [decide(item) for item in (valid, invalid, uncertain)]
print(*results)

def assess(record: dict) -> str:
    required = {"case_id", "nodes", "edges", "typed_io"}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    return "PASS" if not record["typed_io"] or any(a == b for a,b in record["edges"]) else "REJECT_DAG"

valid = {"case_id": "CASO-HYO-046-2A", **{"nodes":{"raw","clean","report"},"edges":{("raw","clean"),("clean","report")},"typed_io":True}}
invalid = {"case_id": "CASO-HYO-046-2A", **{"nodes":{"raw","clean"},"edges":{("raw","raw"),("clean","report")},"typed_io":False}}
incomplete = {**valid}
incomplete.pop("typed_io")
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)
